package com.bank.ea.domain;
import jakarta.persistence.*; import java.time.Instant;
@Entity @Table(name="audit_events") public class AuditEvent { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @Column(nullable=false,updatable=false) private String actor; @Column(nullable=false,updatable=false) private String action; @Column(nullable=false,updatable=false) private String entityType; @Column(nullable=false,updatable=false) private String entityId; @Column(length=2000,updatable=false) private String detail; @Column(nullable=false,updatable=false) private Instant occurredAt=Instant.now(); protected AuditEvent(){} public AuditEvent(String a,String b,String c,String d,String e){actor=a;action=b;entityType=c;entityId=d;detail=e;} public Long getId(){return id;} public String getActor(){return actor;} public String getAction(){return action;} public String getEntityType(){return entityType;} public String getEntityId(){return entityId;} public String getDetail(){return detail;} public Instant getOccurredAt(){return occurredAt;} }
